<?php require_once __DIR__.'/../includes/ecosystem.php'; $beyondWallet = beyond_app_bootstrap('API Hub'); $page_title='API Hub v2.0'; require_once __DIR__.'/../includes/header.php';
if($_SERVER['REQUEST_METHOD']==='POST'){ require_login(); verify_csrf(); $name=trim($_POST['name']??'Default Key'); $key='bos_'.bin2hex(random_bytes(24)); db()->prepare('INSERT INTO api_keys (user_id, name, api_key, created_at) VALUES (?,?,?,?)')->execute([current_user()['id'],$name,password_hash($key,PASSWORD_DEFAULT),now()]); flash('success','API key created. Copy now: '.$key); redirect('api-hub/'); }
$keys=[]; if(is_logged_in()){ $stmt=db()->prepare('SELECT id,name,created_at,last_used_at FROM api_keys WHERE user_id=? ORDER BY id DESC'); $stmt->execute([current_user()['id']]); $keys=$stmt->fetchAll(); }
?>
